import React from 'react';
import { motion } from 'framer-motion';
import './RecentActivity.css';

const RecentActivity = ({ analytics }) => {
  const recentPredictions = analytics?.recent_predictions || [];

  return (
    <motion.div
      className="recent-activity"
      initial={{ opacity: 0, x: -20 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ delay: 0.4 }}
    >
      <h3>Recent Activity</h3>
      <div className="activity-list">
        {recentPredictions.slice(-10).reverse().map((prediction, index) => (
          <motion.div
            key={index}
            className={`activity-item ${prediction.risk_level === 'HIGH RISK' ? 'high-risk' : 'low-risk'}`}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5 + index * 0.1 }}
            whileHover={{ x: 5, transition: { duration: 0.2 } }}
          >
            <div className={`risk-badge ${prediction.risk_level === 'HIGH RISK' ? 'high' : 'low'}`}>
              {prediction.risk_level}
            </div>
            <div className="activity-details">
              <div className="probability">{prediction.probability}%</div>
              <div className="timestamp">
                {new Date(prediction.timestamp).toLocaleTimeString()}
              </div>
            </div>
          </motion.div>
        ))}
      </div>
    </motion.div>
  );
};

export default RecentActivity;
